// 六个算术运算符
console.log(10 + 3);    // 13   加法
console.log(10 - 3);    // 7    减法
console.log(10 * 3);    // 30   乘法
console.log(10 / 3);    // 3.333...  浮点除法
console.log(10 % 3);    // 1    取余（余数）
console.log(2 ** 10);   // 1024 幂运算（2的10次方）

// % 取余的经典用途
const n = 7;
console.log(n % 2 === 0 ? "偶数" : "奇数"); // "奇数"

// 循环索引
const colors = ["red", "green", "blue"];
for (let i = 0; i < 10; i++) {
  console.log(colors[i % 3]); // 循环取 red,green,blue
}

// ❌ 隐式转换导致拼接
console.log("3" + 4);     // "34" 不是 7！

// ✅ 用 Number() 显式转换
console.log(Number("3") + 4);  // 7

// ✅ 用 parseInt() 提取整数
console.log(parseInt("10px"));  // 10

// ✅ 一元 + 快速转数字
console.log(+"3" + 4);         // 7

// == 会做类型转换，结果常常违反直觉
1 == "1"          // true  — "1"被转为数字1
0 == false        // true  — 两边都转为0
"" == 0           // true  — 空字符串转为0
null == undefined // true  — 特殊规则
[] == false       // true  — [] → "" → 0, false → 0

// 这些都是 true，但极其令人困惑！
// 你无法记住所有转换规则，也没必要记

// && 与 — 左边为假，直接返回左边（不执行右边）
console.log(0 && "hello");      // 0（0 是 falsy，短路返回 0）
console.log(1 && "hello");      // "hello"（1 是 truthy，返回右边）

// || 或 — 左边为真，直接返回左边（不执行右边）
console.log(1 || "hello");      // 1（1 是 truthy，短路返回 1）
console.log(0 || "hello");      // "hello"（0 是 falsy，返回右边）

// ! 非 — 取反，返回 true/false
console.log(!0);    // true
console.log(!1);    // false
console.log(!!"hi"); // true（!! 双取反 = 转布尔值）

// 1. 默认值
const name = user.name || "匿名";   // name 为空则用默认值

// 2. 条件执行
isReady && startProcess();           // isReady 为 true 才执行

// 3. 安全访问（替代 if）
const city = user && user.address && user.address.city;

// 4. 可选链 ?. 更优雅（ES2020）
const city2 = user?.address?.city;   // 推荐！

// || 的问题：0 和 "" 是 falsy，会被误判为空
const count = 0;
console.log(count || 10);    // 10 ❌ 0被当成空了！

// ?? 只对 null/undefined 生效，0 和 "" 不受影响
console.log(count ?? 10);    // 0  ✅ 正确保留 0

// 对比
null ?? "默认"    // "默认" ✅
undefined ?? "默认" // "默认" ✅
0 ?? "默认"       // 0 ✅
"" ?? "默认"      // "" ✅

// 基础赋值
let x = 10;        // = 赋值

// 复合赋值（简写）
x += 5;            // 等价于 x = x + 5 → 15
x -= 3;            // 等价于 x = x - 3 → 12
x *= 2;            // 等价于 x = x * 2 → 24
x /= 4;            // 等价于 x = x / 4 → 6
x %= 4;            // 等价于 x = x % 4 → 2
x **= 3;           // 等价于 x = x ** 3 → 8

// 逻辑赋值（ES2021）
let a = null;
a ||= "默认值";    // a 为 falsy，赋值 → "默认值"

let b = 0;
b ??= 100;         // b 为 0（不是 null/undefined），不赋值 → 0

// 语法：条件 ? 真值 : 假值
const age = 20;
const status = age >= 18 ? "成年" : "未成年";
console.log(status); // "成年"

// 常见用途：条件渲染、默认值、条件赋值
const theme = isDark ? "dark" : "light";
const label = items.length > 0 ? `${items.length}项` : "空";

// 嵌套三元（可读性差，不推荐）
const grade = score >= 90 ? "A" : score >= 80 ? "B" : "C";
// 上面虽然合法，但建议用 if/else 替代

// 常见优先级（从高到低）
// 1. () 括号 — 最高
// 2. ** 幂
// 3. * / % 乘除取余
// 4. + - 加减
// 5. > < >= <= 比较
// 6. === !== 相等
// 7. && 与
// 8. || 或
// 9. ? : 三元
// 10. = 赋值 — 最低

// 例子
1 + 2 * 3         // 7（先乘后加）
(1 + 2) * 3       // 9（括号优先）

2 ** 3 ** 2       // 512（幂运算从右到左：2^(3^2)=2^9）

true || false && false  // true（&& 优先于 ||）
// 等价于：true || (false && false) → true || false → true

// 规则1：永远用 ===
if (x === 10) { ... }  // ✅
if (x == 10) { ... }   // ❌ 永远不要

// 规则2：运算前显式转类型
const num = Number(str);      // 字符串 → 数字
const str = String(num);      // 数字 → 字符串
const bool = Boolean(val);    // 任意 → 布尔

// 规则3：判断 NaN 用 Number.isNaN
if (Number.isNaN(x)) { ... }  // ✅
if (x === NaN) { ... }        // ❌ 永远 false

// 规则4：拿不准就加括号
const result = (a + b) * c;   // ✅ 清晰
const result = a + b * c;     // ⚠️ 需要想优先级

// ── 算术 ──
+  -  *  /  %  **
// ⚠️ + 遇字符串做拼接，其他运算符会转数字

// ── 比较 ──
===  !==   // ✅ 推荐！类型+值都必须相同
>  <  >=  <=
==  !=     // ❌ 禁用！会做类型转换

// ── 逻辑 ──
&&  // 与：左边为真返回右边，为假返回左边
||  // 或：左边为真返回左边，为假返回右边
!   // 非：取反
??  // 空值合并：只有 null/undefined 才用默认值 ✅

// ── 赋值 ──
=  +=  -=  *=  /=  %=  **=
||=  ??=  // ES2021 逻辑赋值

// ── 三元 ──
条件 ? 真值 : 假值  // 简单二选一用，别嵌套
